import React, { useState, useEffect, useCallback } from 'react';
import './CreateCombinedMaterial.css';

const CombinedMaterialInputForm = ({
    onClose,
    fetchAPI,
    apiBaseUrl,
    onMaterialAdded,
}) => {
    const initialComboMat = {
        name: '',
        description: '',
        submaterials: [],
    };

    const [comboMat, setComboMat] = useState(initialComboMat);
    const [error, setError] = useState(null);
    const [materials, setMaterials] = useState([]);
    const [materialChanges, setMaterialChanges] = useState([]);
    const [submaterials, setSubmaterials] = useState([]);

    const fetchData = useCallback(async () => {
        try {
            console.log('Fetching materials and material changes...');
            const MaterialData = await fetchAPI(`${apiBaseUrl}/materiallist`);
            const materialChangesData = await fetchAPI(`${apiBaseUrl}/materialchangesAPI`);
            setMaterials(MaterialData);
            setMaterialChanges(materialChangesData);
            console.log('Materials and material changes fetched:', MaterialData, materialChangesData);
        } catch (error) {
            console.error('Error fetching data:', error);
            setError(error.message);
        }
    }, [fetchAPI, apiBaseUrl]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleChange = (e) => {
        const { name, value } = e.target;
        console.log(`Handling change for ${name} with value ${value}`);
        setComboMat((prevComboMat) => ({
            ...prevComboMat,
            [name]: value,
        }));
    };

    const handleSubmaterialChange = async (index, field, value) => {
        console.log(`Handling submaterial change for index ${index}, field ${field}, value ${value}`);
        const updatedSubmaterials = [...submaterials];
        updatedSubmaterials[index][field] = value;
        setComboMat((prevComboMat) => ({
            ...prevComboMat,
            submaterials: updatedSubmaterials,
        }));
    };

    const saveCombinedMaterial = async () => {
        try {
            console.log('Saving combined material:', comboMat);
            const combinedMaterialPayload = {
                name: comboMat.name,
                description: comboMat.description,
            };

            const combinedMaterialResponse = await fetchAPI(`${apiBaseUrl}/combinedMaterials`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(combinedMaterialPayload),
            });
            
            console.log('Combined Material Response:', combinedMaterialResponse); // Log the full response
            
            if (combinedMaterialResponse.ok) {
                const responseData = await combinedMaterialResponse.json(); // Parse the JSON response
                if (responseData.success) {
                    // Handle success
                    const { combined_material_id } = responseData; // Adjust based on actual response structure
                    // ... rest of your success handling code ...
                } else {
                    // Handle API-reported failure
                    console.error('API reported failure:', responseData);
                    alert(`Error creating combined material: ${responseData.message || 'Unknown error'}`);
                }
            } else {
                // Handle HTTP-level failure
                console.error('HTTP error status:', combinedMaterialResponse.status);
                alert('Error creating combined material: HTTP status ' + combinedMaterialResponse.status);
            }
            

            const { combined_material_id } = await combinedMaterialResponse;
            console.log('Combined material ID:', combined_material_id);

            const submaterialsWithCombinedMaterialId = submaterials.map(submaterial => ({
                ...submaterial,
                combined_material_id,
            }));

            console.log('Submaterials with combined material ID:', submaterialsWithCombinedMaterialId);
            const submaterialsPayload = submaterialsWithCombinedMaterialId.map(submaterial => ({
                combined_material_id: submaterial.combined_material_id,
                material_id: submaterial.materialId,
                multiplier: submaterial.multiplier,
            }));

            const submaterialsResponse = await fetchAPI(`${apiBaseUrl}/saveCombinedMaterial`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(submaterialsPayload),
            });

            if (submaterialsResponse.ok) {
                console.log('Combined material and submaterials saved successfully!');
                alert('Combined material and submaterials saved successfully!');
                setComboMat(initialComboMat);
                onMaterialAdded();
                onClose();
            } else {
                const responseData = await submaterialsResponse;
                console.error('Error creating submaterials:', responseData.error);
                alert(`Error creating submaterials: ${responseData.error}`);
            }
        } catch (error) {
            console.error('Error in saveCombinedMaterial:', error);
            alert(`Error: ${error.message}`);
        }
    };

    const addMaterial = () => {
        console.log('Adding a new material');
        setSubmaterials((prevSubmaterials) => [
            ...prevSubmaterials,
            { materialId: '', multiplier: 0, unitPrice: 0 },
        ]);
    };

    const removeMaterial = (index) => {
        console.log(`Removing material at index ${index}`);
        const updatedMaterials = submaterials.filter((_, i) => i !== index);
        setSubmaterials(updatedMaterials);
    };

    if (error) return <div>Error: {error}</div>;

    return (
        <div className="material-input-form">
            <h3>Combine Materials</h3>
            <span className="close-popup" onClick={onClose}>
                &times;
            </span>
            <div className="form-row">
                <div className="form-group">
                    <label htmlFor="comboName">Combo Name</label>
                    <input
                        id="comboName"
                        type="text"
                        name="name"
                        value={comboMat.name}
                        onChange={handleChange}
                        placeholder="Enter combined material name"
                        className="form-control"
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="description">Description</label>
                    <textarea
                        id="description"
                        name="description"
                        value={comboMat.description}
                        onChange={handleChange}
                        placeholder="Enter Description"
                        className="form-control"
                    />
                </div>
            </div>

            {materials.length > 0 &&
                submaterials.map((selection, index) => (
                    <div key={index} className="material-selection">
                        <div className="form-row">
                            <div className="form-group">
                                <label>Material</label>
                                <select
                                    value={selection.materialId}
                                    onChange={(e) => handleSubmaterialChange(index, 'materialId', e.target.value)}
                                    className="form-control"
                                >
                                    <option value="">Select Material</option>
                                    {materials.map(material => (
                                        <option key={material.matid} value={material.matid}>{material.name}</option>
                                    ))}
                                </select>
                            </div>
                            <div className="form-group">
                                <label>Multiplier</label>
                                <input
                                    type="number"
                                    value={selection.multiplier}
                                    onChange={(e) => handleSubmaterialChange(index, 'multiplier', e.target.value)}
                                    className="form-control"
                                />
                            </div>
                            <div className="price-remove-container">
                                <div className="unit-price">
                                    <span>
                                        Unit Price: {parseFloat(selection.unitPrice).toFixed(2)}
                                    </span>
                                </div>
                            </div>
                            <div className="price-remove-container">
                                {submaterials.length > 1 && (
                                    <button
                                        className="remove-btn"
                                        onClick={() => removeMaterial(index)}
                                    >
                                        Remove
                                    </button>
                                )}
                            </div>
                        </div>
                    </div>
                ))}
            <button className="btn btn-primary add-btn" onClick={addMaterial}>
                Add Material
            </button>
            <button className="btn btn-success save-btn" onClick={saveCombinedMaterial}>
                Save Combined Material
            </button>
        </div>
    );
};

export default CombinedMaterialInputForm;
